import pytest
import requests

def test_multiple_errors():
    base_url = "http://localhost:8080"
    params = {"user_id": 123, "image": "invalid_base64"}
    response = requests.get(f"{base_url}/api/v2/enroll", json=params, timeout=10)
    assert response.json().get("success") == False
    assert response.json().get("error_code") < 0

def test_fuzzy_identification():
    base_url = "http://localhost:8080"
    params = {"user_id": None, "image": "truncated_base64"}
    response = requests.post(f"{base_url}/api/v2/identify", json=params, timeout=10)
    assert response.json().get("success") == False
    assert response.json().get("error_code") < 0